#include <iostream>
#include <vector>

void summarize(const std::vector<int>& values, int& minimum, int& maximum) {
    minimum = maximum = values.front();
    for (int value : values) { if (value < minimum) minimum = value; if (value > maximum) maximum = value; }
}

int main() {
    std::size_t count{};
    if (!(std::cin >> count) || count == 0 || count > 100) return 1;
    std::vector<int> values(count);
    for (int& value : values) if (!(std::cin >> value)) return 1;
    int minimum{}, maximum{};
    summarize(values, minimum, maximum);
    std::cout << minimum << ' ' << maximum << '\n';
}
